mapper.select:
SELECT ac.id, ac.name, ac.description, ac.plan_id as planId, ac.target_type as targetType, ac.template_id as templateId, ac.category_id as categoryId, ac.deduction_item_id as deductionItemId, ac.check_record_id as checkRecordId, ac.department_id as departmentId, ac.class_id as classId, ac.org_scope_type as orgScopeType, ac.time_range_type as timeRangeType, ac.fixed_start_date as fixedStartDate, ac.fixed_end_date as fixedEndDate, ac.dynamic_range as dynamicRange, ac.sort_order as sortOrder, ac.status, ac.created_by as createdBy, ac.created_at as createdAt, ac.updated_at as updatedAt, u.real_name as createdByName, cp.plan_name as planName, CASE ac.target_type WHEN 'PLAN' THEN cp.plan_name WHEN 'TEMPLATE' THEN ct.template_name WHEN 'CATEGORY' THEN cc.category_name WHEN 'DEDUCTION_ITEM' THEN di.item_name WHEN 'SINGLE_CHECK' THEN dc.check_name WHEN 'ORGANIZATION' THEN COALESCE(d.dept_name, cl.class_name) END as targetName, CASE ac.target_type WHEN 'PLAN' THEN '按检查计划' WHEN 'TEMPLATE' THEN '按检查模板' WHEN 'CATEGORY' THEN '按检查类别' WHEN 'DEDUCTION_ITEM' THEN '按扣分项' WHEN 'SINGLE_CHECK' THEN '按单次检查' WHEN 'ORGANIZATION' THEN '按组织' END as targetTypeName FROM analysis_configs ac LEFT JOIN users u ON ac.created_by = u.id LEFT JOIN check_plans cp ON ac.plan_id = cp.id LEFT JOIN check_templates ct ON ac.target_type = 'TEMPLATE' AND ac.template_id = ct.id LEFT JOIN check_categories cc ON ac.target_type = 'CATEGORY' AND ac.category_id = cc.id LEFT JOIN deduction_items di ON ac.target_type = 'DEDUCTION_ITEM' AND ac.deduction_item_id = di.id LEFT JOIN daily_checks dc ON ac.target_type = 'SINGLE_CHECK' AND ac.check_record_id = dc.id LEFT JOIN departments d ON ac.target_type = 'ORGANIZATION' AND ac.department_id = d.id LEFT JOIN classes cl ON ac.target_type = 'ORGANIZATION' AND ac.class_id = cl.id
ac.deleted = 0
AND ac.name LIKE CONCAT('%', #{query.name}, '%')
AND ac.target_type = #{query.targetType}
AND ac.status = #{query.status}
ORDER BY ac.sort_order ASC, ac.created_at DESC

SELECT cl.id as classId, cl.class_name as className, COUNT(DISTINCT dcd.id) as deductionCount, SUM(dcd.deduct_score) as totalDeduction, AVG(dcd.deduct_score) as avgDeduction FROM daily_check_details dcd JOIN daily_checks dc ON dcd.check_id = dc.id AND dc.deleted = 0 JOIN classes cl ON dcd.class_id = cl.id WHERE dcd.deleted = 0 AND dc.check_date BETWEEN #{startDate} AND #{endDate}
AND dc.template_id = #{targetId}
AND dcd.category_id = #{targetId}
AND dcd.deduction_item_id = #{targetId}
GROUP BY cl.id, cl.class_name ORDER BY totalDeduction DESC
LIMIT #{limit}

SELECT s.id as studentId, s.student_no as studentNo, u.real_name as studentName, cl.class_name as className, COUNT(*) as deductionCount, SUM(dcd.deduct_score) as totalDeduction FROM daily_check_details dcd JOIN daily_checks dc ON dcd.check_id = dc.id AND dc.deleted = 0 JOIN classes cl ON dcd.class_id = cl.id JOIN students s ON FIND_IN_SET(s.id, dcd.student_ids) > 0 JOIN users u ON s.user_id = u.id WHERE dcd.deleted = 0 AND dcd.student_ids IS NOT NULL AND dcd.student_ids != '' AND dc.check_date BETWEEN #{startDate} AND #{endDate}
AND dc.template_id = #{targetId}
AND dcd.category_id = #{targetId}
AND dcd.deduction_item_id = #{targetId}
GROUP BY s.id, s.student_no, u.real_name, cl.class_name ORDER BY totalDeduction DESC
LIMIT #{limit}

SELECT dc.check_date as checkDate, COUNT(DISTINCT dc.id) as checkCount, COUNT(dcd.id) as deductionCount, COALESCE(SUM(dcd.deduct_score), 0) as totalDeduction FROM daily_checks dc LEFT JOIN daily_check_details dcd ON dc.id = dcd.check_id AND dcd.deleted = 0 LEFT JOIN classes cl ON dcd.class_id = cl.id WHERE dc.deleted = 0 AND dc.check_date BETWEEN #{startDate} AND #{endDate}
AND dc.template_id = #{targetId}
AND dcd.category_id = #{targetId}
AND dcd.deduction_item_id = #{targetId}
GROUP BY dc.check_date ORDER BY dc.check_date ASC

SELECT DATE_FORMAT(dc.check_date, '%Y-%m-%d') as dateStr, COALESCE(di.item_name, cc.category_name) as itemName, COUNT(*) as count, SUM(dcd.deduct_score) as totalDeduction FROM daily_check_details dcd JOIN daily_checks dc ON dcd.check_id = dc.id AND dc.deleted = 0 LEFT JOIN deduction_items di ON dcd.deduction_item_id = di.id LEFT JOIN check_categories cc ON dcd.category_id = cc.id LEFT JOIN classes cl ON dcd.class_id = cl.id WHERE dcd.deleted = 0 AND dc.check_date BETWEEN #{startDate} AND #{endDate}
AND dc.template_id = #{targetId}
AND dcd.category_id = #{targetId}
GROUP BY dateStr, COALESCE(di.item_name, cc.category_name) ORDER BY dateStr ASC

SELECT COUNT(DISTINCT dc.id) as totalChecks, COUNT(dcd.id) as totalDeductions, COUNT(DISTINCT dcd.class_id) as classCount, COALESCE(SUM(dcd.deduct_score), 0) as totalDeduction, COALESCE(AVG(dcd.deduct_score), 0) as avgDeduction, COALESCE(MAX(dcd.deduct_score), 0) as maxDeduction, COALESCE(MIN(CASE WHEN dcd.deduct_score > 0 THEN dcd.deduct_score END), 0) as minDeduction FROM daily_checks dc LEFT JOIN daily_check_details dcd ON dc.id = dcd.check_id AND dcd.deleted = 0 LEFT JOIN classes cl ON dcd.class_id = cl.id WHERE dc.deleted = 0 AND dc.check_date BETWEEN #{startDate} AND #{endDate}
AND dc.template_id = #{targetId}
AND dcd.category_id = #{targetId}
AND dcd.deduction_item_id = #{targetId}
AND dc.id = #{targetId}
